input:
node build_alarm_fatigue.mjs && node --input-type=module <<'EOF'
import fs from 'node:fs/promises';
import path from 'node:path';
import { FileBlob, SpreadsheetFile } from '@oai/artifact-tool';
const wb = await SpreadsheetFile.importXlsx(await FileBlob.load(path.resolve('[EXCLUDED_GENERATED_ARTIFACT]')));
await fs.mkdir('[EXCLUDED_GENERATED_ARTIFACT]', { recursive: true });
for (const sheetName of ['Report','Calc','Packet','Assumptions']) {
  const blob = await wb.render({ sheetName, autoCrop: 'all', scale: 1, format: 'png' });
  await fs.writeFile(`[EXCLUDED_GENERATED_ARTIFACT]}.png`, new Uint8Array(await blob.arrayBuffer()));
}
const errors = await wb.inspect({ kind: 'match', searchTerm: '#REF!|#DIV/0!|#VALUE!|#NAME\\?|#N/A', options: { useRegex: true, maxResults: 50 }, summary: 'error scan' });
console.log(errors.ndjson);
EOF

